import fetchGlobalSSHKeyRequest from "git/requests/fetchGlobalSSHKeyRequest";
import type {
  GenerateSSHKeyRequestParams,
  GenerateSSHKeyResponse,
} from "git/requests/generateSSHKeyRequest.types";
import type { FetchGlobalSSHKeyInitPayload } from "git/store/actions/fetchGlobalSSHKeyActions";
import { gitGlobalActions } from "git/store/gitGlobalSlice";
import { selectGitApiContractsEnabled } from "git/store/selectors/gitFeatureFlagSelectors";
import type { GitArtifactPayloadAction } from "git/store/types";
import { call, put, select } from "redux-saga/effects";
import { validateResponse } from "sagas/ErrorSagas";
import handleApiErrors from "./helpers/handleApiErrors";

export function* fetchGlobalSSHKeySaga(
  action: GitArtifactPayloadAction<FetchGlobalSSHKeyInitPayload>,
) {
  let response: GenerateSSHKeyResponse | undefined;

  try {
    const params: GenerateSSHKeyRequestParams = {
      keyType: action.payload.keyType,
    };

    const isGitApiContractsEnabled: boolean = yield select(
      selectGitApiContractsEnabled,
    );

    response = yield call(
      fetchGlobalSSHKeyRequest,
      params,
      isGitApiContractsEnabled,
    );
    const isValidResponse: boolean = yield validateResponse(response);

    if (response && isValidResponse) {
      yield put(
        gitGlobalActions.fetchGlobalSSHKeySuccess({
          responseData: response.data,
        }),
      );
    }
  } catch (e) {
    const error = handleApiErrors(e as Error, response);

    if (error) {
      yield put(gitGlobalActions.fetchGlobalSSHKeyError({ error }));
    }
  }
}

import mergeRequest from "git/requests/mergeRequest";
import type { MergeResponse } from "git/requests/mergeRequest.types";
import type { MergeInitPayload } from "git/store/actions/mergeActions";
import { gitArtifactActions } from "git/store/gitArtifactSlice";
import { selectGitApiContractsEnabled } from "git/store/selectors/gitFeatureFlagSelectors";
import type { GitArtifactPayloadAction } from "git/store/types";
import { call, put, select } from "redux-saga/effects";
import { validateResponse } from "sagas/ErrorSagas";
import handleApiErrors from "./helpers/handleApiErrors";

export default function* mergeSaga(
  action: GitArtifactPayloadAction<MergeInitPayload>,
) {
  const { artifactDef, artifactId } = action.payload;
  let response: MergeResponse | undefined;

  try {
    const params = {
      sourceBranch: action.payload.sourceBranch,
      destinationBranch: action.payload.destinationBranch,
    };

    const isGitApiContractsEnabled: boolean = yield select(
      selectGitApiContractsEnabled,
    );

    response = yield call(
      mergeRequest,
      artifactDef.artifactType,
      artifactId,
      params,
      isGitApiContractsEnabled,
    );

    const isValidResponse: boolean = yield validateResponse(response);

    if (isValidResponse) {
      yield put(gitArtifactActions.mergeSuccess({ artifactDef }));
    }
  } catch (e) {
    const error = handleApiErrors(e as Error, response);

    if (error) {
      yield put(gitArtifactActions.mergeError({ artifactDef, error }));
    }
  }
}

import type { ExecutorContext } from '@nx/devkit';
import {
  createTmpTsConfig,
  DependentBuildableProjectNode,
} from '@nx/js/internal';
import { NgPackagr } from 'ng-packagr';
import { join, resolve } from 'path';
import { createLibraryExecutor } from '../package/package.impl';
import type { BuildAngularLibraryExecutorOptions } from '../package/schema';
import { parseRemappedTsConfigAndMergeDefaults } from '../utilities/typescript';
import { getNgPackagrInstance } from './ng-packagr-adjustments/ng-packagr';

async function initializeNgPackgrLite(
  options: BuildAngularLibraryExecutorOptions,
  context: ExecutorContext,
  projectDependencies: DependentBuildableProjectNode[]
): Promise<NgPackagr> {
  const ngPackagr = await getNgPackagrInstance();
  ngPackagr.forProject(resolve(context.root, options.project));

  if (options.tsConfig) {
    const remappedTsConfigFilePath = createTmpTsConfig(
      join(context.root, options.tsConfig),
      context.root,
      context.projectsConfigurations.projects[context.projectName].root,
      projectDependencies
    );
    const tsConfig = await parseRemappedTsConfigAndMergeDefaults(
      context.root,
      options.tsConfig,
      remappedTsConfigFilePath
    );
    ngPackagr.withTsConfig(tsConfig);
  }

  return ngPackagr;
}

export const ngPackagrLiteExecutor = createLibraryExecutor(
  initializeNgPackgrLite
);

export default ngPackagrLiteExecutor;

import type { Tree } from '@nx/devkit';
import {
  formatFiles,
  installPackagesTask,
  readProjectConfiguration,
} from '@nx/devkit';
import { assertSupportedAngularVersion } from '../../utils/assert-supported-angular-version';
import {
  addDependencies,
  addHydration,
  addServerFile,
  generateSSRFiles,
  generateTsConfigServerJsonForBrowserBuilder,
  normalizeOptions,
  setRouterInitialNavigation,
  setServerTsConfigOptionsForApplicationBuilder,
  updateProjectConfigForApplicationBuilder,
  updateProjectConfigForBrowserBuilder,
  validateOptions,
} from './lib';
import type { Schema } from './schema';

export async function setupSsr(tree: Tree, schema: Schema) {
  assertSupportedAngularVersion(tree);
  validateOptions(tree, schema);
  const options = await normalizeOptions(tree, schema);

  if (!schema.skipPackageJson) {
    addDependencies(tree, options.isUsingApplicationBuilder);
  }
  generateSSRFiles(tree, options);

  if (options.hydration) {
    addHydration(tree, options);
  }

  if (!options.hydration) {
    setRouterInitialNavigation(tree, options);
  }

  if (options.isUsingApplicationBuilder) {
    updateProjectConfigForApplicationBuilder(tree, options);
    setServerTsConfigOptionsForApplicationBuilder(tree, options);
  } else {
    updateProjectConfigForBrowserBuilder(tree, options);
    generateTsConfigServerJsonForBrowserBuilder(tree, options);
  }

  addServerFile(tree, options);

  if (!options.skipFormat) {
    await formatFiles(tree);
  }

  return () => {
    installPackagesTask(tree);
  };
}

export default setupSsr;

import { type Tree } from '@nx/devkit';
import {
  getDeclaredPackageVersion,
  getInstalledPackageVersion,
} from '@nx/devkit/internal';
import { major } from 'semver';

export const nxVersion = require('../../package.json').version;

export const minSupportedExpressVersion = '4.0.0';

// Fresh-install constants (latest supported major).
export const expressVersion = '^5.1.0';
export const expressTypingsVersion = '^5.0.0';

type ExpressVersions = {
  expressVersion: string;
  expressTypingsVersion: string;
};

const latestVersions: ExpressVersions = {
  expressVersion,
  expressTypingsVersion,
};

type CompatVersions = 4;
const versionMap: Record<CompatVersions, ExpressVersions> = {
  4: {
    expressVersion: '^4.21.2',
    expressTypingsVersion: '^4.17.21',
  },
};

export function versions(tree: Tree): ExpressVersions {
  const installedExpressVersion = getInstalledExpressVersion(tree);
  if (!installedExpressVersion) {
    return latestVersions;
  }
  const expressMajorVersion = major(installedExpressVersion);
  return versionMap[expressMajorVersion as CompatVersions] ?? latestVersions;
}

export function getInstalledExpressVersion(tree?: Tree): string | null {
  if (!tree) {
    return getInstalledPackageVersion('express');
  }
  return getDeclaredPackageVersion(tree, 'express');
}

import { Socket } from 'net';
import { performance } from 'perf_hooks';
import { serializeResult } from '../socket-utils';
import { serverLogger } from '../logger';
import { getCachedSerializedProjectGraphPromise } from './project-graph-incremental-recomputation';
import { HandlerResult } from './server';

export async function handleRequestProjectGraph(
  socket: Socket
): Promise<HandlerResult> {
  try {
    performance.mark('server-connection');
    serverLogger.requestLog('Client Request for Project Graph Received');

    const result = await getCachedSerializedProjectGraphPromise(socket);
    if (result.error) {
      return {
        description: `Error when preparing serialized project graph.`,
        error: result.error,
      };
    }

    const serializedResult = serializeResult(
      result.error,
      result.serializedProjectGraph,
      result.serializedSourceMaps
    );
    if (!serializedResult) {
      return {
        description: `Error when serializing project graph result.`,
        error: new Error(
          'Critical error when serializing server result, check server logs'
        ),
      };
    }

    performance.mark('serialized-project-graph-ready');
    performance.measure(
      'total for creating and serializing project graph',
      'server-connection',
      'serialized-project-graph-ready'
    );

    return { response: serializedResult, description: 'project-graph' };
  } catch (e) {
    return {
      description: `Unexpected error when creating Project Graph.`,
      error: e,
    };
  }
}

import type { DeleteVersions, FlattenedField } from 'payload'

import { APIError, buildVersionCollectionFields, buildVersionGlobalFields } from 'payload'

import type { MongooseAdapter } from './index.js'
import type { CollectionModel } from './types.js'

import { buildQuery } from './queries/buildQuery.js'
import { getCollection, getGlobal } from './utilities/getEntity.js'
import { getSession } from './utilities/getSession.js'

export const deleteVersions: DeleteVersions = async function deleteVersions(
  this: MongooseAdapter,
  { collection: collectionSlug, globalSlug, locale, req, where },
) {
  let fields: FlattenedField[]
  let VersionsModel: CollectionModel

  if (globalSlug) {
    const { globalConfig, Model } = getGlobal({
      adapter: this,
      globalSlug,
      versions: true,
    })
    fields = buildVersionGlobalFields(this.payload.config, globalConfig, true)
    VersionsModel = Model
  } else if (collectionSlug) {
    const { collectionConfig, Model } = getCollection({
      adapter: this,
      collectionSlug,
      versions: true,
    })
    fields = buildVersionCollectionFields(this.payload.config, collectionConfig, true)
    VersionsModel = Model
  } else {
    throw new APIError('Either collection or globalSlug must be passed.')
  }

  const query = await buildQuery({
    adapter: this,
    fields,
    locale,
    where,
  })

  const session = await getSession(this, req)

  await VersionsModel.deleteMany(query, { session })
}

import type {
  DataFromGlobalSlug,
  GlobalSlug,
  PayloadRequest,
  SanitizedGlobalConfig,
  SelectType,
} from 'payload'
import type { DeepPartial } from 'ts-essentials'

import { isolateObjectProperty, updateOperationGlobal } from 'payload'

import type { Context } from '../types.js'

type Resolver<TSlug extends GlobalSlug> = (
  _: unknown,
  args: {
    data?: DeepPartial<Omit<DataFromGlobalSlug<TSlug>, 'id'>>
    draft?: boolean
    fallbackLocale?: string
    locale?: string
  },
  context: {
    req: PayloadRequest
  },
) => Promise<DataFromGlobalSlug<TSlug>>

export function update<TSlug extends GlobalSlug>(
  globalConfig: SanitizedGlobalConfig,
): Resolver<TSlug> {
  return async function resolver(_, args, context: Context) {
    if (args.locale) {
      context.req.locale = args.locale
    }
    if (args.fallbackLocale) {
      context.req.fallbackLocale = args.fallbackLocale
    }

    const { slug } = globalConfig

    const options = {
      slug,
      data: args.data,
      depth: 0,
      draft: args.draft,
      globalConfig,
      req: isolateObjectProperty(context.req, 'transactionID'),
    }

    const result = await updateOperationGlobal<TSlug, SelectType>(options)
    return result
  }
}

import path from 'node:path'

import type { FetchFunction, FetchOptions } from '@pnpm/fetching.fetcher-base'
import gfs from '@pnpm/fs.graceful-fs'
import type { Cafs } from '@pnpm/store.cafs-types'
import type { StoreIndex } from '@pnpm/store.index'
import { addFilesFromTarball } from '@pnpm/worker'

const isAbsolutePath = /^\/|^[A-Z]:/i

interface Resolution {
  integrity?: string
  registry?: string
  tarball: string
}

export function createLocalTarballFetcher (storeIndex: StoreIndex): FetchFunction {
  const fetch = (cafs: Cafs, resolution: Resolution, opts: FetchOptions) => {
    const tarball = resolvePath(opts.lockfileDir, resolution.tarball.slice(5))
    const buffer = gfs.readFileSync(tarball)
    return addFilesFromTarball({
      storeDir: cafs.storeDir,
      storeIndex,
      buffer,
      filesIndexFile: opts.filesIndexFile,
      integrity: resolution.integrity,
      readManifest: opts.readManifest,
      url: tarball,
      pkg: opts.pkg,
      appendManifest: opts.appendManifest,
      ignoreFilePattern: opts.ignoreFilePattern,
    })
  }

  return fetch as FetchFunction
}

function resolvePath (where: string, spec: string): string {
  if (isAbsolutePath.test(spec)) return spec
  return path.resolve(where, spec)
}

import type { Config } from '@pnpm/config.reader'
import type { ResolutionVerifier } from '@pnpm/resolving.resolver-base'
import type { StoreController } from '@pnpm/store.controller'
import { getStorePath } from '@pnpm/store.path'

import { createNewStoreController, type CreateNewStoreControllerOptions } from './createNewStoreController.js'

export { createNewStoreController }

export type CreateStoreControllerOptions = Omit<CreateNewStoreControllerOptions, 'storeDir'> & Pick<Config,
| 'storeDir'
| 'dir'
| 'pnpmHomeDir'
| 'workspaceDir'
>

export interface StoreControllerHandle {
  ctrl: StoreController
  dir: string
  resolutionVerifiers: ResolutionVerifier[]
}

export async function createStoreControllerCached (
  storeControllerCache: Map<string, Promise<StoreControllerHandle>>,
  opts: CreateStoreControllerOptions
): Promise<StoreControllerHandle> {
  const storeDir = await getStorePath({
    pkgRoot: opts.dir,
    storePath: opts.storeDir,
    pnpmHomeDir: opts.pnpmHomeDir,
  })
  if (!storeControllerCache.has(storeDir)) {
    storeControllerCache.set(storeDir, createStoreController(opts))
  }
  return await storeControllerCache.get(storeDir) as StoreControllerHandle
}

export async function createStoreController (
  opts: CreateStoreControllerOptions
): Promise<StoreControllerHandle> {
  const storeDir = await getStorePath({
    pkgRoot: opts.workspaceDir ?? opts.dir,
    storePath: opts.storeDir,
    pnpmHomeDir: opts.pnpmHomeDir,
  })
  return createNewStoreController(Object.assign(opts, {
    storeDir,
  }))
}

import type { SerializedCoverageConfig } from '../runtime/config'
import type { RuntimeCoverageModuleLoader } from '../utils/coverage'
import { resolveCoverageProviderModule } from '../utils/coverage'

export async function startCoverageInsideWorker(
  options: SerializedCoverageConfig,
  loader: RuntimeCoverageModuleLoader,
  runtimeOptions: { isolate: boolean },
): Promise<unknown> {
  const coverageModule = await resolveCoverageProviderModule(options, loader)

  if (coverageModule) {
    return coverageModule.startCoverage?.({
      ...runtimeOptions,
      autoAttachSubprocess: options.autoAttachSubprocess,
      reportsDirectory: options.reportsDirectory,
    })
  }

  return null
}

export async function takeCoverageInsideWorker(
  options: SerializedCoverageConfig,
  loader: RuntimeCoverageModuleLoader,
): Promise<unknown> {
  const coverageModule = await resolveCoverageProviderModule(options, loader)

  if (coverageModule) {
    return coverageModule.takeCoverage?.({ moduleExecutionInfo: loader.moduleExecutionInfo })
  }

  return null
}

export async function stopCoverageInsideWorker(
  options: SerializedCoverageConfig,
  loader: RuntimeCoverageModuleLoader,
  runtimeOptions: { isolate: boolean },
): Promise<unknown> {
  const coverageModule = await resolveCoverageProviderModule(options, loader)

  if (coverageModule) {
    return coverageModule.stopCoverage?.(runtimeOptions)
  }

  return null
}

